            className="w-full bg-gray-100 border-none rounded-2xl py-4 pl-12 pr-4 focus:ring-2 focus:ring-green-500 text-sm transition-all"
          />
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
        </div>

        {/* Promo Banner */}
        <div className="bg-green-500 rounded-3xl p-6 relative overflow-hidden flex justify-between items-center text-white min-h-[160px]">
          <div className="relative z-10 flex flex-col gap-4">
            <div className="flex flex-col">
              <span className="text-3xl font-extrabold tracking-tight">New</span>
              <span className="text-3xl font-extrabold tracking-tight">Product</span>
            </div>
            <button className="bg-white text-green-600 px-6 py-2 rounded-xl text-sm font-bold w-fit active:scale-95 transition-transform">
              Buy
            </button>
          </div>
          <div className="absolute right-0 bottom-[-20px] w-32 h-44 z-0 opacity-90 transform rotate-[-5deg]">
            <img 
              src="https://picsum.photos/seed/promo/300/500" 
              alt="Promo" 
              className="w-full h-full object-contain rounded-2xl shadow-2xl"
            />
          </div>
        </div>

        {/* Categories */}
        <div className="flex gap-3 overflow-x-auto no-scrollbar py-2">
          {CATEGORIES.map(cat => (
            <button
              key={cat}
              onClick={() => setActiveCategory(cat)}
              className={`px-5 py-2 rounded-full text-xs font-semibold whitespace-nowrap transition-all ${
