            <div className="col-span-2 text-center py-12 text-gray-500 italic">
              No products found in this category.
            </div>
          )}
        </div>
      </div>
    </Layout>
  );
};

export default Home;

import React, { useState, useEffect } from 'react';
import Layout from '../components/Layout';
import { Search as SearchIcon, Sparkles, Loader2 } from 'lucide-react';
import { MOCK_PRODUCTS } from '../constants';
import ProductCard from '../components/ProductCard';
import { getRecommendedProducts } from '../services/geminiService';
import { Product } from '../types';

const Search: React.FC = () => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<Product[]>([]);
  const [isSearching, setIsSearching] = useState(false);

  useEffect(() => {
    const delayDebounceFn = setTimeout(async () => {
      if (query.trim()) {
        setIsSearching(true);
        const recommended = await getRecommendedProducts(query, MOCK_PRODUCTS);
        setResults(recommended);
        setIsSearching(false);
      } else {
        setResults([]);
      }
    }, 500);

    return () => clearTimeout(delayDebounceFn);
  }, [query]);

  return (
    <Layout title="Search">
      <div className="flex flex-col gap-6 py-2">
        <div className="relative">
          <input
            type="text"
            placeholder="Search products with AI..."
            autoFocus
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            className="w-full bg-white border border-gray-200 rounded-2xl py-4 pl-12 pr-4 focus:ring-2 focus:ring-green-500 text-sm shadow-sm"
          />
          <SearchIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
          {isSearching && (
            <Loader2 className="absolute right-4 top-1/2 -translate-y-1/2 text-green-500 animate-spin" size={20} />
          )}
        </div>

        {!query && (
          <div className="flex flex-col gap-4">
            <h3 className="text-sm font-bold text-gray-900 flex items-center gap-2">
              <Sparkles size={16} className="text-yellow-500" />
              Popular Searches
            </h3>
            <div className="flex flex-wrap gap-2">
              {['iPhone', 'MacBook', 'Headphones', 'Lego'].map(tag => (
                <button 
                  key={tag}
                  onClick={() => setQuery(tag)}
                  className="bg-gray-100 hover:bg-gray-200 px-4 py-2 rounded-xl text-xs font-medium text-gray-600"
                >
                  {tag}
                </button>
              ))}
            </div>
          </div>
        )}

        {results.length > 0 && (
          <div className="flex flex-col gap-4">
            <h3 className="text-sm font-bold text-gray-900">Search Results</h3>
            <div className="grid grid-cols-2 gap-4">
              {results.map(p => (
                <ProductCard key={p.id} product={p} />
              ))}
            </div>
          </div>
        )}

        {query && results.length === 0 && !isSearching && (
          <div className="text-center py-12 text-gray-400">
            No results found for "{query}"
          </div>
        )}
      </div>
    </Layout>
  );
};

export default Search;

import React, { useState } from 'react';
import Layout from '../components/Layout';
import { useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';
import { CheckCircle, ArrowLeft } from 'lucide-react';

const Checkout: React.FC = () => {
  const { totalPrice, cart, clearCart } = useCart();
  const { user, addOrder } = useAuth();
  const navigate = useNavigate();
  const [isOrdered, setIsOrdered] = useState(false);
  const [formData, setFormData] = useState({
    fullName: user?.name || '',
    phone: '',
    address: '',
    city: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.address || !formData.phone) return alert('Please fill required fields');

    addOrder({
      id: Math.random().toString(36).substr(2, 9),
      items: cart,
      total: totalPrice,
      status: 'Pending',
      date: new Date().toLocaleDateString(),
      address: formData.address
    });

    setIsOrdered(true);
    setTimeout(() => {
      clearCart();
      navigate('/profile');
    }, 2500);
  };

  if (isOrdered) {
    return (
      <div className="fixed inset-0 bg-white z-50 flex flex-col items-center justify-center p-6 text-center max-w-md mx-auto">
        <div className="w-20 h-20 bg-green-100 text-green-500 rounded-full flex items-center justify-center mb-6 animate-bounce">
          <CheckCircle size={48} />
        </div>
        <h2 className="text-2xl font-bold text-gray-900 mb-2">Order Confirmed!</h2>
        <p className="text-gray-500">Your items are being processed and will reach you soon.</p>
        <div className="mt-8 text-sm text-gray-400">Redirecting to profile...</div>
      </div>
    );
  }

  return (
    <Layout title="Checkout">
      <form onSubmit={handleSubmit} className="flex flex-col gap-6 py-4">
        <button onClick={() => navigate(-1)} type="button" className="flex items-center gap-2 text-gray-500 text-sm font-medium mb-2">
          <ArrowLeft size={18} />
          Back to Cart
        </button>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-50 flex flex-col gap-4">
          <h3 className="text-lg font-bold text-gray-900">Delivery Address</h3>

          <div className="flex flex-col gap-2">
            <label className="text-xs font-bold text-gray-500">Full Name</label>
            <input 
              required
              type="text" 
              className="bg-gray-50 border border-gray-100 rounded-xl p-3 text-sm focus:ring-2 focus:ring-green-500"
              value={formData.fullName}
              onChange={(e) => setFormData({...formData, fullName: e.target.value})}
            />
          </div>

          <div className="flex flex-col gap-2">
            <label className="text-xs font-bold text-gray-500">Phone Number</label>
            <input 
              required
              type="tel" 
              className="bg-gray-50 border border-gray-100 rounded-xl p-3 text-sm focus:ring-2 focus:ring-green-500"
              placeholder="+1 234 567 890"
              value={formData.phone}
              onChange={(e) => setFormData({...formData, phone: e.target.value})}
            />
          </div>

          <div className="flex flex-col gap-2">
            <label className="text-xs font-bold text-gray-500">Detailed Address</label>
            <textarea 
              required
              rows={3}
              className="bg-gray-50 border border-gray-100 rounded-xl p-3 text-sm focus:ring-2 focus:ring-green-500"
              placeholder="Building, street, and apartment number"
              value={formData.address}
              onChange={(e) => setFormData({...formData, address: e.target.value})}
            />
          </div>

          <div className="flex flex-col gap-2">
            <label className="text-xs font-bold text-gray-500">City</label>
            <input 
              required
              type="text" 
              className="bg-gray-50 border border-gray-100 rounded-xl p-3 text-sm focus:ring-2 focus:ring-green-500"
              value={formData.city}
              onChange={(e) => setFormData({...formData, city: e.target.value})}
            />
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-50">
          <h3 className="text-lg font-bold text-gray-900 mb-4">Payment Method</h3>
          <div className="p-4 border-2 border-green-500 rounded-2xl bg-green-50 flex justify-between items-center">
            <span className="font-bold text-green-700">Cash on Delivery</span>
            <CheckCircle size={20} className="text-green-500" />
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-50 flex flex-col gap-4 mb-10">
          <div className="flex justify-between items-center">
            <span className="text-lg font-bold text-gray-900">Amount Due</span>
            <span className="text-2xl font-extrabold text-gray-900">${totalPrice.toFixed(2)}</span>
          </div>
          <button type="submit" className="w-full bg-green-500 text-white py-4 rounded-2xl font-bold shadow-lg shadow-green-100 active:scale-95 transition-all">
            Place Order
          </button>
        </div>
      </form>
    </Layout>
  );
};

export default Checkout;

