interface LayoutProps {
  children: ReactNode;
  title?: string;
}

interface Notification {
  id: string;
  title: string;
  message: string;
  time: string;
  isRead: boolean;
}

const Layout: React.FC<LayoutProps> = ({ children, title = 'Home' }) => {
  const { totalItems } = useCart();
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isNotificationsOpen, setIsNotificationsOpen] = useState(false);
  const [notifications, setNotifications] = useState<Notification[]>([
    {
      id: '1',
      title: 'Welcome to ChinaFlyBD!',
      message: 'Get the best products directly from China at wholesale prices.',
      time: 'Just now',
      isRead: false
    },
    {
      id: '2',
      title: 'Flash Sale Alert',
      message: 'Up to 50% off on premium office chairs. Check them out!',
      time: '2 hours ago',
      isRead: false
    },
    {
      id: '3',
      title: 'Order Delivered',
      message: 'Your recent order #CF1023 has been delivered successfully.',
      time: 'Yesterday',
      isRead: true
    }
  ]);

  const navigate = useNavigate();
  const notificationRef = useRef<HTMLDivElement>(null);

  const unreadCount = notifications.filter(n => !n.isRead).length;

  const markAllAsRead = () => {
    setNotifications(prev => prev.map(n => ({ ...n, isRead: true })));
  };

  const clearNotifications = () => {
    setNotifications([]);
    setIsNotificationsOpen(false);
  };

  // Close notifications when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setIsNotificationsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Categories are all removed per request
  const menuItems: any[] = [];

  return (
    <div className="flex flex-col min-h-screen bg-gray-50 max-w-md mx-auto relative shadow-xl overflow-hidden font-sans">
      {/* Side Menu Drawer */}
      <div 
        className={`fixed inset-0 z-50 transition-all duration-300 ${isMenuOpen ? 'visible opacity-100' : 'invisible opacity-0'}`}
      >
        <div 
          className="absolute inset-0 bg-black/60 backdrop-blur-sm"
          onClick={() => setIsMenuOpen(false)}
        />

        <div 
          className={`absolute top-0 left-0 h-full w-72 bg-white shadow-2xl transition-transform duration-300 ease-out transform ${isMenuOpen ? 'translate-x-0' : '-translate-x-full'}`}
