import React, { ReactNode, useState, useRef, useEffect, createContext, useContext } from 'react';
import { NavLink, useNavigate, useLocation } from 'react-router-dom';
import { 
  Home, ShoppingCart, User, Bell, Package, Menu, X, 
  ChevronRight, Grid 
} from 'lucide-react';
import { useCart } from '../context/CartContext';
import { CATEGORIES } from '../constants';

// Context to share active category with Home page
export const CategoryContext = createContext<{
  activeCategory: string;
  setActiveCategory: (cat: string) => void;
}>({ activeCategory: 'All', setActiveCategory: () => {} });

interface LayoutProps {
  children: ReactNode;
  title?: string;
}

interface Notification {
  id: string;
  title: string;
  message: string;
  time: string;
  isRead: boolean;
}

const Layout: React.FC<LayoutProps> = ({ children, title = 'Home' }) => {
  const { totalItems } = useCart();
  const [activeCategory, setActiveCategory] = useState('All');
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isNotificationsOpen, setIsNotificationsOpen] = useState(false);
  const [isCategoriesDrawerOpen, setIsCategoriesDrawerOpen] = useState(false);
  const [notifications, setNotifications] = useState<Notification[]>([
    {
      id: '1',
      title: 'Welcome to ChinaFlyBD!',
      message: 'Get the best products directly from China at wholesale prices.',
      time: 'Just now',
      isRead: false
    }
  ]);

  const navigate = useNavigate();
  const location = useLocation();
  const notificationRef = useRef<HTMLDivElement>(null);

  const unreadCount = notifications.filter(n => !n.isRead).length;

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setIsNotificationsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    setIsCategoriesDrawerOpen(false);
    setIsMenuOpen(false);
  }, [location.pathname]);

  const handleCategorySelect = (cat: string) => {
    setActiveCategory(cat);
    setIsCategoriesDrawerOpen(false);
    if (location.pathname !== '/') {
      navigate('/');
    }
  };

  return (
    <CategoryContext.Provider value={{ activeCategory, setActiveCategory }}>
      <div className="flex flex-col min-h-screen bg-gray-50 max-w-md mx-auto relative shadow-xl overflow-hidden font-sans">

        {/* --- Main Sidebar Overlay --- */}
        <div className={`fixed inset-0 z-50 transition-all duration-300 ${isMenuOpen ? 'visible opacity-100' : 'invisible opacity-0'}`}>
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setIsMenuOpen(false)} />
          <div className={`absolute top-0 left-0 h-full w-72 bg-white shadow-2xl transition-transform duration-300 ease-out transform ${isMenuOpen ? 'translate-x-0' : '-translate-x-full'}`}>
            <div className="flex flex-col h-full">
              <div className="p-5 border-b border-gray-100 flex justify-between items-center bg-[#e62e04] text-white">
                <div className="flex flex-col leading-tight">
                  <span className="text-xl font-black tracking-tighter italic">CHINAFLY BD</span>
                  <span className="text-[10px] opacity-80 uppercase tracking-widest">Global Sourcing Hub</span>
                </div>
                <button onClick={() => setIsMenuOpen(false)} className="p-2 hover:bg-black/10 rounded-full transition-colors"><X size={24} /></button>
              </div>
              <div className="flex-1 py-4 px-5">
                <NavLink to="/" className="flex items-center gap-4 py-4 text-gray-700 font-semibold text-sm border-b border-gray-50">
                  <Home size={20} className="text-gray-400" /> Home
                </NavLink>
                <button onClick={() => { setIsMenuOpen(false); setIsCategoriesDrawerOpen(true); }} className="w-full flex items-center gap-4 py-4 text-gray-700 font-semibold text-sm border-b border-gray-50 text-left">
                  <Grid size={20} className="text-gray-400" /> Browse Categories
                </button>
                <NavLink to="/orders" className="flex items-center gap-4 py-4 text-gray-700 font-semibold text-sm border-b border-gray-50">
                  <Package size={20} className="text-gray-400" /> My Orders
                </NavLink>
              </div>
            </div>
          </div>
        </div>

        {/* --- CATEGORY SIDE DRAWER (Matches Screenshot) --- */}
        <div className={`fixed inset-0 z-50 transition-all duration-300 ${isCategoriesDrawerOpen ? 'visible opacity-100' : 'invisible opacity-0'}`}>
          <div className="absolute inset-0 bg-black/50 backdrop-blur-[1px]" onClick={() => setIsCategoriesDrawerOpen(false)} />
          <div 
            className={`absolute top-0 left-0 h-full w-72 bg-white shadow-2xl transition-transform duration-300 ease-out transform ${isCategoriesDrawerOpen ? 'translate-x-0' : '-translate-x-full'}`}
          >
            <div className="flex flex-col h-full">
              {/* Drawer Header */}
              <div className="p-4 border-b border-gray-100 flex items-center gap-3">
                <button onClick={() => setIsCategoriesDrawerOpen(false)} className="p-1 text-gray-400 hover:text-gray-800 transition-colors">
                  <X size={24} />
                </button>
                <span className="text-sm font-black text-gray-800 uppercase tracking-widest">Shop Categories</span>
              </div>

              {/* Drawer Body - Categories with Circular Thumbnails */}
              <div className="flex-1 overflow-y-auto no-scrollbar py-2">
                <button 
                  onClick={() => handleCategorySelect('All')}
                  className={`w-full flex items-center gap-4 px-5 py-3 transition-colors border-b border-gray-50 ${activeCategory === 'All' ? 'bg-red-50' : 'hover:bg-gray-50'}`}
                >
                  <div className="w-12 h-12 rounded-full bg-gray-100 flex items-center justify-center text-[#e62e04]">
                    <Grid size={24} />
                  </div>
                  <span className={`text-[13px] font-bold ${activeCategory === 'All' ? 'text-[#e62e04]' : 'text-gray-700'}`}>All Products</span>
                </button>

                {CATEGORIES.map((cat, idx) => (
                  <button
                    key={cat}
                    onClick={() => handleCategorySelect(cat)}
                    className={`w-full flex items-center gap-4 px-5 py-3 transition-colors border-b border-gray-50 ${activeCategory === cat ? 'bg-red-50' : 'hover:bg-gray-50'}`}
                  >
                    <div className="w-12 h-12 rounded-full overflow-hidden border border-gray-100 bg-gray-50">
                      <img 
                        src={`https://picsum.photos/seed/${cat.replace(/\s/g, '')}/100/100`} 
                        alt={cat}
                        className="w-full h-full object-cover"
                      />
                    </div>
                    <span className={`text-[13px] font-bold text-left flex-1 ${activeCategory === cat ? 'text-[#e62e04]' : 'text-gray-700'}`}>
                      {cat}
                    </span>
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>

        {/* Header */}
        <header className="sticky top-0 z-40 bg-white border-b-2 border-[#e62e04] shadow-sm">
          <div className="px-4 py-3 flex justify-between items-center relative">
            <div className="flex items-center gap-2">
              <button onClick={() => setIsMenuOpen(true)} className="p-1.5 text-gray-800 hover:bg-gray-100 rounded-lg transition-colors">
                <Menu size={28} />
              </button>
              <div className="flex flex-col leading-none">
                <span className="text-lg font-black text-[#e62e04] tracking-tighter italic">CHINAFLY</span>
                <span className="text-[8px] font-bold text-gray-900 tracking-[0.2em] uppercase">BD STORE</span>
              </div>
            </div>

            <div className="flex items-center gap-1">
              <button onClick={() => setIsNotificationsOpen(!isNotificationsOpen)} className="p-2 text-gray-700 relative hover:bg-gray-50 rounded-full transition-colors">
                <Bell size={22} />
                {unreadCount > 0 && (
                  <span className="absolute top-1.5 right-1.5 w-4 h-4 bg-[#e62e04] text-white text-[8px] font-bold rounded-full border border-white flex items-center justify-center animate-pulse">
                    {unreadCount}
                  </span>
                )}
              </button>
              <NavLink to="/profile" className="p-2 text-gray-700 hover:bg-gray-50 rounded-full transition-colors">
                <User size={22} />
              </NavLink>
            </div>

            {/* Notifications Overlay */}
            {isNotificationsOpen && (
              <div ref={notificationRef} className="absolute top-full right-4 w-72 bg-white shadow-2xl border border-gray-100 rounded-b-xl overflow-hidden z-50 animate-in slide-in-from-top-2 duration-200">
                <div className="bg-gray-50 px-4 py-3 flex justify-between items-center border-b border-gray-100">
                  <span className="text-xs font-black text-gray-800 uppercase tracking-widest">Notifications</span>
                  <button onClick={() => setNotifications([])} className="text-[10px] font-bold text-[#e62e04] uppercase hover:underline">Clear</button>
                </div>
                <div className="max-h-80 overflow-y-auto">
                  {notifications.length > 0 ? (
                    notifications.map(n => (
                      <div key={n.id} className="p-4 border-b border-gray-50 flex flex-col gap-1 hover:bg-gray-50 transition-colors">
                        <div className="flex justify-between items-start gap-2">
                          <span className="text-[11px] font-bold text-gray-800">{n.title}</span>
                          <span className="text-[9px] text-gray-400 whitespace-nowrap">{n.time}</span>
                        </div>
                        <p className="text-[11px] text-gray-500 leading-normal">{n.message}</p>
                      </div>
                    ))
                  ) : (
                    <div className="p-10 text-center text-xs text-gray-400">No notifications</div>
                  )}
                </div>
              </div>
            )}
          </div>
        </header>

        {/* Main Content */}
        <main className="flex-1 pb-24 overflow-y-auto">
          {children}
        </main>

        {/* Bottom Nav */}
        <nav className="fixed bottom-0 left-1/2 -translate-x-1/2 w-full max-w-md bg-white border-t border-gray-200 px-1 py-2 flex justify-around items-center z-40 shadow-[0_-4px_10px_rgba(0,0,0,0.1)]">
          <NavLink to="/" onClick={() => setActiveCategory('All')} className={({ isActive }) => `flex flex-col items-center gap-0.5 px-2 py-1 transition-all ${isActive && !isCategoriesDrawerOpen ? 'text-[#e62e04]' : 'text-gray-400'}`}>
            <Home size={20} />
            <span className="text-[8px] font-bold">HOME</span>
          </NavLink>
          <button 
            onClick={() => setIsCategoriesDrawerOpen(!isCategoriesDrawerOpen)}
            className={`flex flex-col items-center gap-0.5 px-2 py-1 transition-all ${isCategoriesDrawerOpen ? 'text-[#e62e04]' : 'text-gray-400'}`}
          >
            <Grid size={20} />
            <span className="text-[8px] font-bold">CATEGORY</span>
          </button>
          <NavLink to="/orders" className={({ isActive }) => `flex flex-col items-center gap-0.5 px-2 py-1 transition-all ${isActive ? 'text-[#e62e04]' : 'text-gray-400'}`}>
            <Package size={20} />
            <span className="text-[8px] font-bold">ORDERS</span>
          </NavLink>
          <NavLink to="/cart" className={({ isActive }) => `flex flex-col items-center gap-0.5 px-2 py-1 relative transition-all ${isActive ? 'text-[#e62e04]' : 'text-gray-400'}`}>
            <div className="relative">
              <ShoppingCart size={20} />
              {totalItems > 0 && (
                <span className="absolute -top-1.5 -right-1.5 bg-[#e62e04] text-white text-[8px] w-4 h-4 rounded-full flex items-center justify-center font-bold border border-white">
                  {totalItems}
                </span>
              )}
            </div>
            <span className="text-[8px] font-bold">CART</span>
          </NavLink>
          <NavLink to="/profile" className={({ isActive }) => `flex flex-col items-center gap-0.5 px-2 py-1 transition-all ${isActive ? 'text-[#e62e04]' : 'text-gray-400'}`}>
            <User size={20} />
            <span className="text-[8px] font-bold">ACCOUNT</span>
          </NavLink>
        </nav>
      </div>
    </CategoryContext.Provider>
  );
};

export default Layout;
export const useCategory = () => useContext(CategoryContext);

import React, { useState, useMemo, useContext } from 'react';
import Layout, { CategoryContext } from '../components/Layout';
import ProductCard from '../components/ProductCard';
import { MOCK_PRODUCTS } from '../constants';
import { Search } from 'lucide-react';

const Home: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const { activeCategory } = useContext(CategoryContext);

  const filteredProducts = useMemo(() => {
    return MOCK_PRODUCTS.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = activeCategory === 'All' || p.category === activeCategory;
      return matchesSearch && matchesCategory;
    });
  }, [searchQuery, activeCategory]);

  return (
    <Layout>
      <div className="p-4 flex flex-col gap-4">
        {/* Main Search Bar */}
        <div className="relative">
          <input
            type="text"
            placeholder="Search products..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full bg-white border-2 border-gray-100 rounded-lg py-3 pl-4 pr-12 focus:border-[#e62e04] focus:ring-0 text-sm transition-all shadow-sm"
          />
          <div className="absolute right-0 top-0 h-full px-4 bg-[#e62e04] rounded-r-lg flex items-center justify-center cursor-pointer">
            <Search className="text-white" size={20} />
          </div>
        </div>

        {/* Promo / Banner Area */}
        <div className="rounded-lg overflow-hidden relative shadow-sm h-32 bg-black">
          <img 
            src="https://picsum.photos/seed/chinafly/800/300" 
            alt="Promo Banner" 
            className="w-full h-full object-cover opacity-70"
          />
          <div className="absolute inset-0 flex flex-col justify-center px-6">
            <span className="text-[#e62e04] text-[10px] font-black uppercase tracking-widest">Flash Sale</span>
            <h2 className="text-white text-xl font-black italic tracking-tighter leading-none">UP TO 50% OFF</h2>
            <p className="text-gray-300 text-[10px] font-bold mt-1">Sourced directly from China</p>
          </div>
        </div>

        {/* Active Filter Indicator */}
        {activeCategory !== 'All' && (
          <div className="flex items-center justify-between bg-gray-100 px-4 py-2 rounded-lg">
            <span className="text-[11px] font-bold text-gray-500 uppercase tracking-widest">
              Category: <span className="text-[#e62e04]">{activeCategory}</span>
            </span>
            <span className="text-[10px] font-bold text-gray-400">{filteredProducts.length} items</span>
          </div>
        )}

        {/* Product Grid */}
        <div className="grid grid-cols-2 gap-2 pb-10">
          {filteredProducts.map(product => (
            <ProductCard key={product.id} product={product} />
          ))}
          {filteredProducts.length === 0 && (
            <div className="col-span-2 text-center py-20 text-gray-400 bg-white rounded-xl border border-dashed border-gray-200">
              <p className="text-sm font-bold">No products found in this category.</p>
              <button onClick={() => setSearchQuery('')} className="text-[#e62e04] text-xs font-bold mt-2">Clear Search</button>
            </div>
          )}
        </div>
      </div>
    </Layout>
  );
};

