                  <Grid size={20} className="text-gray-400" /> Browse Categories
                </button>
                <NavLink to="/orders" className="flex items-center gap-4 py-4 text-gray-700 font-semibold text-sm border-b border-gray-50">
                  <Package size={20} className="text-gray-400" /> My Orders
                </NavLink>
                <NavLink to="/profile" className="flex items-center gap-4 py-4 text-gray-700 font-semibold text-sm border-b border-gray-50">
                  <User size={20} className="text-gray-400" /> My Profile
                </NavLink>
              </div>
            </div>
          </div>
        </div>

        {/* --- CATEGORY SIDE DRAWER --- */}
