                    key={cat}
                    onClick={() => handleCategorySelect(cat)}
                    className={`w-full flex items-center gap-4 px-5 py-3 transition-colors border-b border-gray-50 ${activeCategory === cat ? 'bg-red-50' : 'hover:bg-gray-50'}`}
                  >
                    <div className="w-12 h-12 rounded-full overflow-hidden border border-gray-100 bg-gray-50 flex-shrink-0">
                      <img 
                        src={`https://picsum.photos/seed/${cat.replace(/\s/g, '')}/100/100`} 
                        alt={cat}
                        loading="lazy"
                        className="w-full h-full object-cover"
                      />
