                    <span className={`text-[13px] font-bold text-left flex-1 ${activeCategory === cat ? 'text-[#e62e04]' : 'text-gray-700'}`}>
                      {cat}
                    </span>
                    <ChevronRight size={14} className="text-gray-300" />
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>

        {/* Header */}
        <header className="sticky top-0 z-40 bg-white border-b-2 border-[#e62e04] shadow-sm">
          <div className="px-4 py-3 flex justify-between items-center relative">
            <div className="flex items-center gap-2">
              <button onClick={() => setIsMenuOpen(true)} className="p-1.5 text-gray-800 hover:bg-gray-100 rounded-lg transition-colors">
