              <div className="flex flex-col leading-none" onClick={() => navigate('/')}>
                <span className="text-lg font-black text-[#e62e04] tracking-tighter italic cursor-pointer">CHINAFLY</span>
                <span className="text-[8px] font-bold text-gray-900 tracking-[0.2em] uppercase cursor-pointer">BD STORE</span>
              </div>
            </div>

            <div className="flex items-center gap-1">
              <button onClick={() => setIsNotificationsOpen(!isNotificationsOpen)} className="p-2 text-gray-700 relative hover:bg-gray-50 rounded-full transition-colors">
                <Bell size={22} />
                {unreadCount > 0 && (
                  <span className="absolute top-1.5 right-1.5 w-4 h-4 bg-[#e62e04] text-white text-[8px] font-bold rounded-full border border-white flex items-center justify-center animate-pulse">
                    {unreadCount}
                  </span>
                )}
              </button>
              <NavLink to="/profile" className="p-2 text-gray-700 hover:bg-gray-50 rounded-full transition-colors">
                <User size={22} />
