          </NavLink>
          <NavLink to="/profile" className={({ isActive }) => `flex flex-col items-center gap-0.5 px-2 py-1 transition-all ${isActive ? 'text-[#e62e04]' : 'text-gray-400'}`}>
            <User size={20} />
            <span className="text-[8px] font-bold">ACCOUNT</span>
          </NavLink>
        </nav>
      </div>
    </CategoryContext.Provider>
  );
};

