import React, { useState, useMemo, useContext } from 'react';
import Layout, { CategoryContext } from '../components/Layout';
import ProductCard from '../components/ProductCard';
import { MOCK_PRODUCTS } from '../constants';
import { Search, X } from 'lucide-react';

const Home: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const { activeCategory, setActiveCategory } = useContext(CategoryContext);

  const filteredProducts = useMemo(() => {
    return MOCK_PRODUCTS.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = activeCategory === 'All' || p.category === activeCategory;
      return matchesSearch && matchesCategory;
    });
  }, [searchQuery, activeCategory]);

  return (
    <Layout>
      <div className="p-4 flex flex-col gap-4">
        {/* Main Search Bar */}
        <div className="relative">
          <input
            type="text"
            placeholder="Search products..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full bg-white border-2 border-gray-100 rounded-lg py-3 pl-4 pr-12 focus:border-[#e62e04] focus:ring-0 text-sm transition-all shadow-sm"
          />
          <div className="absolute right-0 top-0 h-full flex items-center">
            {searchQuery && (
              <button onClick={() => setSearchQuery('')} className="p-2 text-gray-300 hover:text-gray-500">
                <X size={18} />
              </button>
            )}
            <div className="h-full px-4 bg-[#e62e04] rounded-r-lg flex items-center justify-center">
              <Search className="text-white" size={20} />
            </div>
          </div>
        </div>

        {/* Promo / Banner Area */}
        {activeCategory === 'All' && !searchQuery && (
          <div className="rounded-lg overflow-hidden relative shadow-sm h-32 bg-black">
            <img 
              src="https://picsum.photos/seed/chinafly/800/300" 
              alt="Promo Banner" 
              className="w-full h-full object-cover opacity-70"
            />
            <div className="absolute inset-0 flex flex-col justify-center px-6">
              <span className="text-[#e62e04] text-[10px] font-black uppercase tracking-widest">Flash Sale</span>
              <h2 className="text-white text-xl font-black italic tracking-tighter leading-none">UP TO 50% OFF</h2>
              <p className="text-gray-300 text-[10px] font-bold mt-1 uppercase tracking-wider">Sourced directly from China</p>
            </div>
          </div>
        )}

        {/* Active Filter Indicator */}
        {(activeCategory !== 'All' || searchQuery) && (
          <div className="flex items-center justify-between bg-white border border-gray-100 px-4 py-3 rounded-lg shadow-sm">
            <div className="flex flex-col">
              <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Active Filtering</span>
              <div className="flex items-center gap-2 mt-0.5">
                {activeCategory !== 'All' && (
                  <span className="text-[11px] font-black text-[#e62e04] uppercase">{activeCategory}</span>
                )}
                {searchQuery && (
                  <span className="text-[11px] font-medium text-gray-600 italic">"{searchQuery}"</span>
                )}
              </div>
            </div>
            <button 
              onClick={() => { setActiveCategory('All'); setSearchQuery(''); }} 
              className="text-[10px] font-black text-gray-400 uppercase hover:text-[#e62e04] transition-colors"
            >
              Clear All
            </button>
          </div>
        )}

        {/* Product Grid */}
        <div className="grid grid-cols-2 gap-2 pb-10">
          {filteredProducts.map(product => (
            <ProductCard key={product.id} product={product} />
          ))}
          {filteredProducts.length === 0 && (
            <div className="col-span-2 text-center py-24 text-gray-400 bg-white rounded-xl border border-dashed border-gray-200">
              <div className="flex justify-center mb-4">
                <Search size={40} className="text-gray-200" />
              </div>
              <p className="text-sm font-bold text-gray-500">No products found.</p>
              <p className="text-[11px] text-gray-400 px-10 mt-1">Try adjusting your filters or search keywords.</p>
              <button 
                onClick={() => { setActiveCategory('All'); setSearchQuery(''); }} 
                className="mt-4 bg-gray-50 px-6 py-2 rounded-full text-[#e62e04] text-[10px] font-black uppercase tracking-widest border border-gray-100"
              >
                Reset Store
              </button>
            </div>
          )}
        </div>
      </div>
    </Layout>
  );
};

