import { useCategory } from '../context/CategoryContext';
import { Search, X, SlidersHorizontal } from 'lucide-react';

const Home: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const { activeCategory, setActiveCategory, setIsDrawerOpen } = useCategory();

  const filteredProducts = useMemo(() => {
    return MOCK_PRODUCTS.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = activeCategory === 'All' || p.category === activeCategory;
      return matchesSearch && matchesCategory;
    });
  }, [searchQuery, activeCategory]);

  return (
    <Layout>
      <div className="p-4 flex flex-col gap-4">
        {/* Main Search Bar - Styled like the screenshot */}
        <div className="flex gap-2">
          <div className="relative flex-1">
            <input
              type="text"
              placeholder="Search anything from China..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full bg-white border border-gray-200 rounded-lg py-2.5 pl-4 pr-10 focus:border-[#e62e04] focus:ring-0 text-sm transition-all shadow-sm"
            />
            {searchQuery ? (
              <button 
                onClick={() => setSearchQuery('')}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-300 hover:text-gray-500"
              >
                <X size={16} />
              </button>
            ) : (
              <div className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400">
                <Search size={18} />
              </div>
            )}
          </div>
          <button 
            onClick={() => setIsDrawerOpen(true)}
            className="bg-[#e62e04] text-white p-2.5 rounded-lg flex items-center justify-center shadow-md shadow-red-100 active:scale-95 transition-all"
          >
            <SlidersHorizontal size={20} />
          </button>
        </div>

        {/* Banner */}
        {activeCategory === 'All' && !searchQuery && (
          <div className="rounded-xl overflow-hidden relative shadow-md h-36 bg-gradient-to-r from-red-600 to-red-400">
            <img 
              src="https://picsum.photos/seed/china/800/400" 
              alt="Promo Banner" 
              className="w-full h-full object-cover opacity-30"
            />
            <div className="absolute inset-0 flex flex-col justify-center px-6 text-white">
              <span className="text-[9px] font-black uppercase tracking-[0.2em] opacity-80 mb-1">Mega Sourcing</span>
              <h2 className="text-2xl font-black italic tracking-tighter leading-none mb-2">CHINA TO BD</h2>
              <div className="flex items-center gap-2">
                <span className="bg-white text-[#e62e04] text-[9px] font-bold px-2 py-0.5 rounded-full uppercase">Wholesale Prices</span>
              </div>
            </div>
          </div>
        )}

        {/* Filter Breadcrumb */}
        {(activeCategory !== 'All' || searchQuery) && (
          <div className="flex items-center justify-between bg-white border border-gray-100 px-4 py-2.5 rounded-xl shadow-sm">
            <div className="flex items-center gap-2 overflow-hidden">
              <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest whitespace-nowrap">Filter:</span>
              <div className="flex gap-1 overflow-x-auto no-scrollbar">
                {activeCategory !== 'All' && (
                  <span className="bg-red-50 text-[#e62e04] text-[10px] font-black px-2 py-0.5 rounded-md border border-red-100 uppercase whitespace-nowrap">
                    {activeCategory}
                  </span>
                )}
                {searchQuery && (
                  <span className="bg-gray-50 text-gray-600 text-[10px] font-bold px-2 py-0.5 rounded-md border border-gray-100 whitespace-nowrap">
                    "{searchQuery}"
                  </span>
                )}
              </div>
            </div>
            <button 
              onClick={() => { setActiveCategory('All'); setSearchQuery(''); }} 
              className="text-[10px] font-black text-gray-400 uppercase hover:text-[#e62e04] ml-2"
            >
              Clear
            </button>
          </div>
        )}

        {/* Grid Title */}
        <div className="flex justify-between items-center px-1">
          <h3 className="text-sm font-black text-gray-800 uppercase tracking-widest">
            {activeCategory === 'All' ? 'Latest Products' : activeCategory}
          </h3>
          <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
            {filteredProducts.length} Items
          </span>
        </div>

        {/* Product Grid */}
        <div className="grid grid-cols-2 gap-3 pb-10">
          {filteredProducts.map(product => (
            <ProductCard key={product.id} product={product} />
          ))}
          {filteredProducts.length === 0 && (
            <div className="col-span-2 text-center py-20 bg-white rounded-2xl border border-dashed border-gray-200">
              <div className="w-16 h-16 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-4 text-gray-300">
                <Search size={32} />
              </div>
              <p className="text-sm font-bold text-gray-500">No items matched your criteria.</p>
              <button 
                onClick={() => { setActiveCategory('All'); setSearchQuery(''); }} 
                className="mt-4 text-[#e62e04] text-[10px] font-black uppercase tracking-widest border border-red-100 px-4 py-2 rounded-full hover:bg-red-50"
              >
                Reset Filter
              </button>
            </div>
          )}
        </div>
      </div>
    </Layout>
  );
};

