  return (
    <Layout title="Checkout">
      <form onSubmit={handleSubmit} className="flex flex-col gap-4 py-4 px-4">
        <button onClick={() => navigate(-1)} type="button" className="flex items-center gap-2 text-gray-500 text-xs font-bold uppercase mb-2">
          <ArrowLeft size={14} />
