          <h3 className="text-sm font-black text-gray-800 uppercase tracking-wider">Shipping Details</h3>

          <div className="flex flex-col gap-1">
            <label className="text-[10px] font-bold text-gray-400 uppercase">Full Name</label>
            <input 
              required
              type="text" 
              className="bg-gray-50 border border-gray-200 rounded p-2.5 text-sm focus:ring-1 focus:ring-[#e62e04] outline-none"
              value={formData.fullName}
              onChange={(e) => setFormData({...formData, fullName: e.target.value})}
            />
          </div>

          <div className="flex flex-col gap-1">
            <label className="text-[10px] font-bold text-gray-400 uppercase">Phone Number</label>
            <input 
              required
              type="tel" 
              className="bg-gray-50 border border-gray-200 rounded p-2.5 text-sm focus:ring-1 focus:ring-[#e62e04] outline-none"
              placeholder="017XXXXXXXX"
              value={formData.phone}
              onChange={(e) => setFormData({...formData, phone: e.target.value})}
            />
          </div>

          <div className="flex flex-col gap-1">
            <label className="text-[10px] font-bold text-gray-400 uppercase">Address</label>
            <textarea 
              required
              rows={2}
              className="bg-gray-50 border border-gray-200 rounded p-2.5 text-sm focus:ring-1 focus:ring-[#e62e04] outline-none"
              placeholder="Street, area, etc."
              value={formData.address}
              onChange={(e) => setFormData({...formData, address: e.target.value})}
            />
          </div>
        </div>

        <div className="bg-white p-5 rounded-lg shadow-sm border border-gray-100">
          <h3 className="text-sm font-black text-gray-800 uppercase tracking-wider mb-3">Order Summary</h3>
          <div className="flex justify-between items-center py-2 border-b border-gray-50">
            <span className="text-xs text-gray-500 uppercase">Subtotal</span>
            <span className="text-sm font-bold text-gray-800">৳{totalPrice.toLocaleString()}</span>
          </div>
          <div className="flex justify-between items-center py-2 border-b border-gray-50">
            <span className="text-xs text-gray-500 uppercase">Shipping</span>
            <span className="text-sm font-bold text-green-600 uppercase">Free</span>
          </div>
          <div className="flex justify-between items-center pt-3">
            <span className="text-sm font-black text-gray-800 uppercase">Total Payable</span>
            <span className="text-lg font-black text-[#e62e04]">৳{totalPrice.toLocaleString()}</span>
          </div>
        </div>

        <button type="submit" className="w-full bg-[#e62e04] text-white py-4 rounded-lg font-black uppercase tracking-widest shadow-lg active:scale-[0.98] transition-all mt-4">
          CONFIRM ORDER
        </button>
      </form>
    </Layout>
  );
};

