import { useAuth } from '../context/AuthContext';
import { MapPin, Plus, Trash2, ArrowLeft, Home, Building, Building2, Map, ChevronDown } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { BD_LOCATIONS } from '../constants';

const Addresses: React.FC = () => {
  const { addresses, addAddress, removeAddress, user } = useAuth();
  const navigate = useNavigate();
  const [showAddForm, setShowAddForm] = useState(false);
  const [formData, setFormData] = useState({
    label: 'Home',
    fullName: user?.name || '',
    phone: '',
    details: '',
    district: '',
    thana: ''
  });

  const districts = Object.keys(BD_LOCATIONS).sort();
  const thanas = formData.district ? BD_LOCATIONS[formData.district].sort() : [];

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.phone || !formData.details || !formData.district || !formData.thana) {
      alert("Please fill all fields including District and Thana");
      return;
    }

    addAddress({
      ...formData,
      id: Math.random().toString(36).substr(2, 9)
    });
    setShowAddForm(false);
    setFormData({ ...formData, phone: '', details: '', district: '', thana: '' });
  };

  const handleDistrictChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setFormData({
      ...formData,
      district: e.target.value,
      thana: '' // Reset thana when district changes
    });
  };

  return (
    <Layout>
      <div className="flex flex-col gap-5 py-5 px-4">
        {/* Header */}
        <div className="flex items-center justify-between px-1">
          <div className="flex items-center gap-3">
            <button onClick={() => navigate(-1)} className="p-2 -ml-2 text-gray-400 dark:text-gray-500 hover:text-gray-800 dark:hover:text-white">
              <ArrowLeft size={20} />
            </button>
            <h2 className="text-sm font-black text-gray-800 dark:text-white uppercase tracking-widest">Saved Addresses</h2>
          </div>
          <button 
            onClick={() => setShowAddForm(!showAddForm)}
            className={`p-2 rounded-xl transition-all ${showAddForm ? 'bg-gray-100 dark:bg-slate-800 text-gray-500' : 'bg-[#e62e04] text-white shadow-lg shadow-red-100 dark:shadow-none'}`}
          >
            {showAddForm ? <ArrowLeft size={20} className="rotate-90" /> : <Plus size={20} />}
          </button>
        </div>

        {/* Add Form */}
        {showAddForm && (
          <form onSubmit={handleSubmit} className="bg-white dark:bg-slate-900 border border-gray-100 dark:border-slate-800 rounded-2xl p-5 shadow-sm animate-in slide-in-from-top-4 duration-300 flex flex-col gap-4">
            <div className="flex flex-col gap-1.5">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Address Label</label>
              <div className="flex gap-2">
                {['Home', 'Office', 'Other'].map(l => (
                  <button 
                    key={l}
                    type="button"
                    onClick={() => setFormData({...formData, label: l})}
                    className={`flex-1 py-2 px-3 rounded-lg text-[10px] font-black uppercase transition-all border ${
                      formData.label === l 
                      ? 'bg-[#e62e04] text-white border-transparent' 
                      : 'bg-gray-50 dark:bg-slate-800 text-gray-400 dark:text-gray-500 border-transparent'
                    }`}
                  >
                    {l}
                  </button>
                ))}
              </div>
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div className="flex flex-col gap-1.5">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Full Name</label>
                <input 
                  type="text" 
                  required
                  value={formData.fullName}
                  onChange={(e) => setFormData({...formData, fullName: e.target.value})}
                  className="w-full bg-gray-50 dark:bg-slate-800 border border-transparent dark:border-slate-700 rounded-xl py-3 px-4 focus:border-[#e62e04] focus:ring-0 text-xs dark:text-white transition-all"
                  placeholder="Name"
                />
              </div>
              <div className="flex flex-col gap-1.5">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Mobile</label>
                <input 
                  type="tel" 
                  required
                  value={formData.phone}
                  onChange={(e) => setFormData({...formData, phone: e.target.value})}
                  className="w-full bg-gray-50 dark:bg-slate-800 border border-transparent dark:border-slate-700 rounded-xl py-3 px-4 focus:border-[#e62e04] focus:ring-0 text-xs dark:text-white transition-all"
                  placeholder="017XXXXXXXX"
                />
              </div>
            </div>

            <div className="flex flex-col gap-1.5">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">District (Jela)</label>
              <div className="relative">
                <select 
                  required
                  value={formData.district}
                  onChange={handleDistrictChange}
                  className="w-full bg-gray-50 dark:bg-slate-800 border border-transparent dark:border-slate-700 rounded-xl py-3 px-4 focus:border-[#e62e04] focus:ring-0 text-xs dark:text-white appearance-none transition-all"
                >
                  <option value="">Select District</option>
                  {districts.map(d => <option key={d} value={d}>{d}</option>)}
                </select>
                <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" size={16} />
              </div>
            </div>

            <div className="flex flex-col gap-1.5">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Thana / Upazila</label>
              <div className="relative">
                <select 
                  required
                  disabled={!formData.district}
                  value={formData.thana}
                  onChange={(e) => setFormData({...formData, thana: e.target.value})}
                  className="w-full bg-gray-50 dark:bg-slate-800 border border-transparent dark:border-slate-700 rounded-xl py-3 px-4 focus:border-[#e62e04] focus:ring-0 text-xs dark:text-white appearance-none transition-all disabled:opacity-50"
                >
                  <option value="">Select Thana</option>
                  {thanas.map(t => <option key={t} value={t}>{t}</option>)}
                </select>
                <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" size={16} />
              </div>
            </div>

            <div className="flex flex-col gap-1.5">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Full Address Details</label>
              <textarea 
                required
                rows={2}
                value={formData.details}
                onChange={(e) => setFormData({...formData, details: e.target.value})}
                className="w-full bg-gray-50 dark:bg-slate-800 border border-transparent dark:border-slate-700 rounded-xl py-3 px-4 focus:border-[#e62e04] focus:ring-0 text-xs dark:text-white transition-all"
                placeholder="House #, Road #, Area..."
              />
            </div>

            <button type="submit" className="w-full bg-[#e62e04] text-white py-3.5 rounded-xl font-black uppercase tracking-widest shadow-lg shadow-red-100 dark:shadow-none active:scale-95 transition-all text-[11px] mt-2">
              Save Delivery Address
            </button>
          </form>
        )}

        {/* Address List */}
        <div className="flex flex-col gap-3 pb-10">
          {addresses.map(addr => (
            <div key={addr.id} className="bg-white dark:bg-slate-900 border border-gray-100 dark:border-slate-800 p-4 rounded-2xl shadow-sm flex items-start gap-4 group transition-all hover:border-gray-200 dark:hover:border-slate-700">
              <div className="w-10 h-10 bg-gray-50 dark:bg-slate-800 rounded-xl flex items-center justify-center text-[#e62e04] flex-shrink-0">
                {addr.label === 'Home' ? <Home size={20} /> : addr.label === 'Office' ? <Building size={20} /> : <MapPin size={20} />}
              </div>
              <div className="flex-1 flex flex-col gap-0.5">
                <div className="flex items-center gap-2">
                  <span className="text-[10px] font-black text-[#e62e04] uppercase tracking-widest">{addr.label}</span>
                  <div className="w-1 h-1 bg-gray-300 rounded-full"></div>
                  <span className="text-[11px] font-bold text-gray-800 dark:text-white">{addr.fullName}</span>
                </div>
                <p className="text-[11px] font-bold text-gray-800 dark:text-gray-100 mt-1">{addr.thana}, {addr.district}</p>
                <p className="text-[10px] text-gray-500 dark:text-gray-400 font-medium leading-relaxed">{addr.details}</p>
                <p className="text-[10px] font-bold text-gray-400 dark:text-gray-500 mt-1">{addr.phone}</p>
              </div>
              <button 
                onClick={() => removeAddress(addr.id)}
                className="p-2 text-gray-300 dark:text-gray-600 hover:text-red-500 dark:hover:text-red-500 transition-colors"
              >
                <Trash2 size={16} />
              </button>
            </div>
          ))}

          {addresses.length === 0 && !showAddForm && (
            <div className="py-20 flex flex-col items-center text-center px-10">
              <div className="w-16 h-16 bg-gray-50 dark:bg-slate-800 rounded-full flex items-center justify-center text-gray-200 dark:text-gray-700 mb-4">
                <MapPin size={32} />
              </div>
              <p className="text-sm font-bold text-gray-400 dark:text-gray-500">No delivery addresses saved yet.</p>
              <button onClick={() => setShowAddForm(true)} className="mt-4 text-[#e62e04] text-[10px] font-black uppercase tracking-widest border border-red-100 dark:border-red-900 px-6 py-2 rounded-full hover:bg-red-50 dark:hover:bg-red-950/20">
                Add Address
              </button>
            </div>
          )}
        </div>
      </div>
    </Layout>
  );
};

export default Addresses;

import React, { useState } from 'react';
import Layout from '../components/Layout';
import { useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';
import { CheckCircle, ArrowLeft, MapPin, ChevronDown, Plus } from 'lucide-react';
import { BD_LOCATIONS } from '../constants';

const Checkout: React.FC = () => {
  const { totalPrice, cart, clearCart } = useCart();
  const { user, addOrder, addresses } = useAuth();
  const navigate = useNavigate();
  const [isOrdered, setIsOrdered] = useState(false);
  const [useSavedAddress, setUseSavedAddress] = useState(addresses.length > 0);
  const [selectedAddressId, setSelectedAddressId] = useState(addresses[0]?.id || '');

  const [formData, setFormData] = useState({
    fullName: user?.name || '',
    phone: '',
    details: '',
    district: '',
    thana: ''
  });

  const districts = Object.keys(BD_LOCATIONS).sort();
  const thanas = formData.district ? BD_LOCATIONS[formData.district].sort() : [];

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    let finalAddressString = "";
    if (useSavedAddress) {
      const addr = addresses.find(a => a.id === selectedAddressId);
      if (!addr) return alert("Please select a valid address");
      finalAddressString = `${addr.fullName}, ${addr.phone}, ${addr.details}, ${addr.thana}, ${addr.district}`;
    } else {
      if (!formData.details || !formData.phone || !formData.district || !formData.thana) {
        return alert('Please fill all required delivery fields');
      }
      finalAddressString = `${formData.fullName}, ${formData.phone}, ${formData.details}, ${formData.thana}, ${formData.district}`;
    }

    addOrder({
      id: Math.random().toString(36).substr(2, 9),
      items: cart,
      total: totalPrice,
      status: 'Pending',
      date: new Date().toLocaleDateString(),
      address: finalAddressString
    });

    setIsOrdered(true);
    setTimeout(() => {
      clearCart();
      navigate('/orders');
    }, 2500);
  };

  if (isOrdered) {
    return (
      <div className="fixed inset-0 bg-white dark:bg-slate-900 z-50 flex flex-col items-center justify-center p-6 text-center max-w-md mx-auto">
        <div className="w-20 h-20 bg-green-100 dark:bg-green-900/30 text-green-500 rounded-full flex items-center justify-center mb-6 animate-bounce">
          <CheckCircle size={48} />
        </div>
        <h2 className="text-2xl font-black text-gray-900 dark:text-white mb-2 italic">Order Confirmed!</h2>
        <p className="text-gray-500 dark:text-gray-400 text-sm">Your order has been placed successfully. Thank you for shopping with MY shopBD.</p>
        <div className="mt-8 text-[10px] font-bold text-gray-400 uppercase tracking-widest">Redirecting to your orders...</div>
      </div>
    );
  }

  return (
    <Layout title="Checkout">
      <form onSubmit={handleSubmit} className="flex flex-col gap-4 py-4 px-4">
        <button onClick={() => navigate(-1)} type="button" className="flex items-center gap-2 text-gray-400 dark:text-gray-500 text-[10px] font-black uppercase mb-2">
          <ArrowLeft size={14} />
          Back to Cart
        </button>

        <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl shadow-sm border border-gray-100 dark:border-slate-800 flex flex-col gap-4">
          <div className="flex justify-between items-center">
            <h3 className="text-sm font-black text-gray-800 dark:text-white uppercase tracking-wider">Shipping Details</h3>
            {addresses.length > 0 && (
              <button 
                type="button" 
                onClick={() => setUseSavedAddress(!useSavedAddress)}
                className="text-[10px] font-black text-[#e62e04] uppercase tracking-tighter border border-red-50 dark:border-red-900/30 px-2 py-1 rounded"
              >
                {useSavedAddress ? 'New Address' : 'Use Saved'}
              </button>
            )}
          </div>

          {useSavedAddress && addresses.length > 0 ? (
            <div className="flex flex-col gap-3">
              {addresses.map(addr => (
                <label 
                  key={addr.id}
                  className={`flex items-start gap-3 p-3 rounded-xl border-2 transition-all cursor-pointer ${
                    selectedAddressId === addr.id 
                    ? 'border-[#e62e04] bg-red-50/30 dark:bg-red-950/10' 
                    : 'border-gray-50 dark:border-slate-800 bg-gray-50/50 dark:bg-slate-800/30'
                  }`}
                >
                  <input 
                    type="radio" 
                    name="address" 
                    className="mt-1 accent-[#e62e04]" 
                    checked={selectedAddressId === addr.id}
                    onChange={() => setSelectedAddressId(addr.id)}
                  />
                  <div className="flex-1 flex flex-col gap-0.5">
                    <span className="text-[11px] font-black text-gray-800 dark:text-white uppercase tracking-tighter">{addr.label} — {addr.fullName}</span>
                    <p className="text-[10px] text-gray-500 dark:text-gray-400 leading-tight">{addr.details}</p>
                    <p className="text-[10px] font-bold text-gray-800 dark:text-gray-200 uppercase">{addr.thana}, {addr.district}</p>
                  </div>
                </label>
              ))}
            </div>
          ) : (
            <>
              <div className="grid grid-cols-2 gap-3">
                <div className="flex flex-col gap-1">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Full Name</label>
                  <input 
                    required
                    type="text" 
                    className="bg-gray-50 dark:bg-slate-800 border-none rounded-xl p-3 text-sm focus:ring-1 focus:ring-[#e62e04] outline-none dark:text-white"
                    value={formData.fullName}
                    onChange={(e) => setFormData({...formData, fullName: e.target.value})}
                  />
                </div>
                <div className="flex flex-col gap-1">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Mobile Number</label>
                  <input 
                    required
                    type="tel" 
                    className="bg-gray-50 dark:bg-slate-800 border-none rounded-xl p-3 text-sm focus:ring-1 focus:ring-[#e62e04] outline-none dark:text-white"
                    placeholder="017XXXXXXXX"
                    value={formData.phone}
                    onChange={(e) => setFormData({...formData, phone: e.target.value})}
                  />
                </div>
              </div>

              <div className="flex flex-col gap-1">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">District (Jela)</label>
                <div className="relative">
                  <select 
                    required
                    className="w-full bg-gray-50 dark:bg-slate-800 border-none rounded-xl p-3 text-sm focus:ring-1 focus:ring-[#e62e04] outline-none dark:text-white appearance-none"
                    value={formData.district}
                    onChange={(e) => setFormData({...formData, district: e.target.value, thana: ''})}
                  >
                    <option value="">Select District</option>
                    {districts.map(d => <option key={d} value={d}>{d}</option>)}
                  </select>
                  <ChevronDown size={16} className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
                </div>
              </div>

              <div className="flex flex-col gap-1">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Thana / Upazila</label>
                <div className="relative">
                  <select 
                    required
                    disabled={!formData.district}
                    className="w-full bg-gray-50 dark:bg-slate-800 border-none rounded-xl p-3 text-sm focus:ring-1 focus:ring-[#e62e04] outline-none dark:text-white appearance-none disabled:opacity-50"
                    value={formData.thana}
                    onChange={(e) => setFormData({...formData, thana: e.target.value})}
                  >
                    <option value="">Select Thana</option>
                    {thanas.map(t => <option key={t} value={t}>{t}</option>)}
                  </select>
                  <ChevronDown size={16} className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
                </div>
              </div>

              <div className="flex flex-col gap-1">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Address Details</label>
                <textarea 
                  required
                  rows={2}
                  className="bg-gray-50 dark:bg-slate-800 border-none rounded-xl p-3 text-sm focus:ring-1 focus:ring-[#e62e04] outline-none dark:text-white"
                  placeholder="Street, area, etc."
                  value={formData.details}
                  onChange={(e) => setFormData({...formData, details: e.target.value})}
                />
              </div>
            </>
          )}
        </div>

        <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl shadow-sm border border-gray-100 dark:border-slate-800">
          <h3 className="text-sm font-black text-gray-800 dark:text-white uppercase tracking-wider mb-3">Order Summary</h3>
          <div className="flex justify-between items-center py-2 border-b border-gray-50 dark:border-slate-800">
            <span className="text-[10px] text-gray-500 uppercase font-bold">Subtotal</span>
            <span className="text-sm font-black text-gray-800 dark:text-white">৳{totalPrice.toLocaleString()}</span>
          </div>
          <div className="flex justify-between items-center py-2 border-b border-gray-50 dark:border-slate-800">
            <span className="text-[10px] text-gray-500 uppercase font-bold">Shipping</span>
            <span className="text-sm font-black text-green-600 uppercase">Free</span>
          </div>
          <div className="flex justify-between items-center pt-3">
            <span className="text-sm font-black text-gray-800 dark:text-white uppercase">Total Payable</span>
            <span className="text-xl font-black text-[#e62e04]">৳{totalPrice.toLocaleString()}</span>
          </div>
        </div>

        <button type="submit" className="w-full bg-[#e62e04] text-white py-4 rounded-xl font-black uppercase tracking-widest shadow-lg shadow-red-100 dark:shadow-none active:scale-[0.98] transition-all mt-2 text-sm">
          CONFIRM ORDER
        </button>
      </form>
    </Layout>
  );
};

export default Checkout;

import React, { useState, useMemo } from 'react';
import Layout from '../components/Layout';
import { useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';
import { CheckCircle, ArrowLeft, ChevronDown } from 'lucide-react';
import { BD_LOCATIONS, DELIVERY_RATES } from '../constants';

const Checkout: React.FC = () => {
  const { totalPrice, cart, clearCart } = useCart();
  const { user, addOrder, addresses } = useAuth();
  const navigate = useNavigate();
  const [isOrdered, setIsOrdered] = useState(false);
  const [useSavedAddress, setUseSavedAddress] = useState(addresses.length > 0);
  const [selectedAddressId, setSelectedAddressId] = useState(addresses[0]?.id || '');

  const [formData, setFormData] = useState({
    fullName: user?.name || '',
    phone: '',
    details: '',
    district: '',
    thana: ''
  });

  const districts = Object.keys(BD_LOCATIONS).sort();
  const thanas = formData.district ? BD_LOCATIONS[formData.district].sort() : [];

  const currentShipping = useMemo(() => {
    let district = '';
    if (useSavedAddress) {
      district = addresses.find(a => a.id === selectedAddressId)?.district || '';
    } else {
      district = formData.district;
    }

    if (!district) return 0;
    return DELIVERY_RATES[district] || DELIVERY_RATES['Default'];
  }, [useSavedAddress, selectedAddressId, formData.district, addresses]);

  const totalPayable = totalPrice + currentShipping;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    let finalAddressString = "";
    if (useSavedAddress) {
      const addr = addresses.find(a => a.id === selectedAddressId);
      if (!addr) return alert("Please select a valid address");
      finalAddressString = `${addr.fullName}, ${addr.phone}, ${addr.details}, ${addr.thana}, ${addr.district}`;
    } else {
      if (!formData.details || !formData.phone || !formData.district || !formData.thana) {
        return alert('Please fill all required delivery fields');
      }
      finalAddressString = `${formData.fullName}, ${formData.phone}, ${formData.details}, ${formData.thana}, ${formData.district}`;
    }

    addOrder({
      id: Math.random().toString(36).substr(2, 9),
      items: cart,
      total: totalPayable,
      status: 'Pending',
      date: new Date().toLocaleDateString(),
      address: finalAddressString
    });

    setIsOrdered(true);
    setTimeout(() => {
      clearCart();
      navigate('/orders');
    }, 2500);
  };

  if (isOrdered) {
    return (
      <div className="fixed inset-0 bg-white dark:bg-slate-900 z-50 flex flex-col items-center justify-center p-6 text-center max-w-md mx-auto">
        <div className="w-20 h-20 bg-green-100 dark:bg-green-900/30 text-green-500 rounded-full flex items-center justify-center mb-6 animate-bounce">
          <CheckCircle size={48} />
        </div>
        <h2 className="text-2xl font-black text-gray-900 dark:text-white mb-2 italic">Order Confirmed!</h2>
        <p className="text-gray-500 dark:text-gray-400 text-sm">Your order has been placed successfully. Thank you for shopping with MY shopBD.</p>
        <div className="mt-8 text-[10px] font-bold text-gray-400 uppercase tracking-widest">Redirecting to your orders...</div>
      </div>
    );
  }

  return (
    <Layout title="Checkout">
      <form onSubmit={handleSubmit} className="flex flex-col gap-4 py-4 px-4 pb-20">
        <button onClick={() => navigate(-1)} type="button" className="flex items-center gap-2 text-gray-400 dark:text-gray-500 text-[10px] font-black uppercase mb-2">
          <ArrowLeft size={14} />
          Back to Cart
        </button>

        <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl shadow-sm border border-gray-100 dark:border-slate-800 flex flex-col gap-4">
          <div className="flex justify-between items-center">
            <h3 className="text-sm font-black text-gray-800 dark:text-white uppercase tracking-wider">Shipping Details</h3>
            {addresses.length > 0 && (
              <button 
                type="button" 
                onClick={() => setUseSavedAddress(!useSavedAddress)}
                className="text-[10px] font-black text-[#e62e04] uppercase tracking-tighter border border-red-50 dark:border-red-900/30 px-2 py-1 rounded"
              >
                {useSavedAddress ? 'New Address' : 'Use Saved'}
              </button>
            )}
          </div>

          {useSavedAddress && addresses.length > 0 ? (
            <div className="flex flex-col gap-3">
              {addresses.map(addr => (
                <label 
                  key={addr.id}
                  className={`flex items-start gap-3 p-3 rounded-xl border-2 transition-all cursor-pointer ${
                    selectedAddressId === addr.id 
                    ? 'border-[#e62e04] bg-red-50/30 dark:bg-red-950/10' 
                    : 'border-gray-50 dark:border-slate-800 bg-gray-50/50 dark:bg-slate-800/30'
                  }`}
